import { useEffect, useState, useMemo } from 'react'
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts'

export interface PaperTrade {
  id: number
  city: string
  target_date: string
  ticker: string
  side: 'YES' | 'NO'
  entry_price: number
  simulated_contracts: number
  simulated_cost: number
  forecast_high_f: number
  implied_temp_f: number
  gap_f: number
  kelly_fraction?: number
  model_spread?: number
  model_confidence?: 'high' | 'medium' | 'low'
  status: 'open' | 'won' | 'lost' | 'expired' | 'settled'
  won?: boolean
  settlement_value?: string
  pnl?: number
  created_at: string
  settled_at?: string
}

const STARTING_BANKROLL = 1000

export default function PaperTrades({ api }: { api: string }) {
  const [trades, setTrades] = useState<PaperTrade[]>([])
  const [loading, setLoading] = useState(true)
  const [settling, setSettling] = useState(false)
  const [paperModeOnly, setPaperModeOnly] = useState(false)

  const load = () => {
    fetch(`${api}/api/paper`)
      .then(r => r.json())
      .then(setTrades)
      .finally(() => setLoading(false))

    fetch(`${api}/api/settings`)
      .then(r => r.json())
      .then(d => setPaperModeOnly(d.paperModeOnly))
      .catch(() => {})
  }

  useEffect(load, [api])

  const settle = async () => {
    setSettling(true)
    await fetch(`${api}/api/paper/settle`, { method: 'POST' })
    load()
    setSettling(false)
  }

  // Handle both schemas for settled trades
  const normalizedTrades = useMemo(() => {
    return trades.map(t => {
      let isSettled = t.status === 'won' || t.status === 'lost' || t.status === 'expired' || t.status === 'settled'
      let isWon = t.status === 'won' || (t.status === 'settled' && t.won === true)
      let pnl = t.pnl
      if (pnl === undefined && isSettled) {
        // Fallback for older schema if pnl is missing but won is present
        if (t.status === 'settled' || t.status === 'won' || t.status === 'lost') {
            pnl = isWon ? (t.simulated_contracts * (1 - t.entry_price)) : -t.simulated_cost
        }
      }
      return { ...t, isSettled, isWon, pnl }
    })
  }, [trades])

  const settled = normalizedTrades.filter(t => t.isSettled)
  const open = normalizedTrades.filter(t => !t.isSettled)
  const won = settled.filter(t => t.isWon)
  const totalPnl = settled.reduce((s, t) => s + (t.pnl ?? 0), 0)
  const totalInvested = settled.reduce((s, t) => s + t.simulated_cost, 0)
  const winRate = settled.length > 0 ? (won.length / settled.length * 100).toFixed(1) : '—'
  const roi = totalInvested > 0 ? (totalPnl / totalInvested * 100).toFixed(1) : '—'
  const roiDisplay = roi === '—' ? '—' : `${parseFloat(roi) > 0 ? '+' : ''}${roi}%`

  // Kelly stats
  const avgKelly = useMemo(() => {
    const withKelly = settled.filter(t => t.kelly_fraction != null)
    if (withKelly.length === 0) return '—'
    return (withKelly.reduce((s, t) => s + t.kelly_fraction!, 0) / withKelly.length * 100).toFixed(1) + '%'
  }, [settled])

  const avgContracts = useMemo(() => {
    if (settled.length === 0) return '—'
    return (settled.reduce((s, t) => s + t.simulated_contracts, 0) / settled.length).toFixed(1)
  }, [settled])

  const avgCost = useMemo(() => {
    if (settled.length === 0) return '—'
    return '$' + (settled.reduce((s, t) => s + t.simulated_cost, 0) / settled.length).toFixed(2)
  }, [settled])

  const confidenceCounts = useMemo(() => {
    let h = 0, m = 0, l = 0
    settled.forEach(t => {
      if (t.model_confidence === 'high') h++
      else if (t.model_confidence === 'medium') m++
      else if (t.model_confidence === 'low') l++
    })
    return { h, m, l }
  }, [settled])

  // Model confidence accuracy
  const confidenceAccuracy = useMemo(() => {
    const calc = (level: 'high' | 'medium' | 'low') => {
      const subset = settled.filter(t => t.model_confidence === level)
      if (subset.length === 0) return null
      const wins = subset.filter(t => t.isWon).length
      return { pct: (wins / subset.length * 100).toFixed(1), total: subset.length }
    }
    return { high: calc('high'), medium: calc('medium'), low: calc('low') }
  }, [settled])

  // Chart data: Cumulative P&L grouped by date
  const chartData = useMemo(() => {
    const sorted = [...settled]
      .filter(t => t.settled_at || t.created_at)
      .sort((a, b) => new Date(a.settled_at || a.created_at).getTime() - new Date(b.settled_at || b.created_at).getTime())

    // Group by date and sum daily P&L
    const dailyMap = new Map<string, number>()
    sorted.forEach(t => {
      const date = (t.settled_at || t.created_at).split('T')[0]
      dailyMap.set(date, (dailyMap.get(date) ?? 0) + (t.pnl ?? 0))
    })

    let cumulative = 0
    return Array.from(dailyMap.entries()).map(([date, dailyPnl]) => {
      cumulative += dailyPnl
      return { date, pnl: parseFloat(cumulative.toFixed(2)) }
    })
  }, [settled])

  // City breakdown
  const cityBreakdown = useMemo(() => {
    const stats: Record<string, { w: number, l: number, pnl: number }> = {}
    settled.forEach(t => {
      if (!stats[t.city]) stats[t.city] = { w: 0, l: 0, pnl: 0 }
      if (t.isWon) stats[t.city].w++
      else stats[t.city].l++
      stats[t.city].pnl += (t.pnl ?? 0)
    })
    return Object.entries(stats).sort((a, b) => b[1].pnl - a[1].pnl)
  }, [settled])

  if (loading) return <div className="text-slate-400">Loading trades...</div>

  return (
    <div className="space-y-6">
      {paperModeOnly && (
        <div className="bg-emerald-500/10 border border-emerald-500/20 text-emerald-400 px-4 py-3 rounded-lg flex items-center gap-2 text-sm font-medium">
          <span>📝</span> Paper Mode Active — No live orders being placed
        </div>
      )}

      {/* Paper Balance */}
      <div className="grid grid-cols-3 gap-4">
        <BalanceCard label="Starting Bankroll" value="$1,000.00" />
        <BalanceCard label="Realized P&L" value={`${totalPnl >= 0 ? '+' : ''}$${totalPnl.toFixed(2)}`} positive={totalPnl >= 0} />
        <BalanceCard label="Current Balance" value={`$${(STARTING_BANKROLL + totalPnl).toFixed(2)}`} positive={STARTING_BANKROLL + totalPnl >= STARTING_BANKROLL} />
      </div>

      {/* Summary cards */}
      <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
        <MiniCard label="Win Rate" value={`${winRate}%`} />
        <MiniCard label="Total P&L" value={`${totalPnl >= 0 ? '+' : ''}$${totalPnl.toFixed(2)}`} positive={totalPnl > 0} />
        <MiniCard label="ROI" value={roiDisplay} positive={roi !== '—' && parseFloat(roi) > 0} />
        <MiniCard label="Trades" value={`${won.length}W / ${settled.length - won.length}L`} />
        <MiniCard label="Total Invested" value={`$${totalInvested.toFixed(2)}`} />
      </div>

      {/* Kelly Stats row */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <MiniCard label="Avg Kelly Fraction" value={avgKelly} />
        <MiniCard label="Avg Contracts/Trade" value={avgContracts} />
        <MiniCard label="Avg Cost/Trade" value={avgCost} />
        <MiniCard label="Model Confidence" value={`${confidenceCounts.h}H / ${confidenceCounts.m}M / ${confidenceCounts.l}L`} />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* P&L Chart */}
        <div className="lg:col-span-2 bg-slate-800 rounded-xl border border-slate-700 p-6">
          <h3 className="text-sm font-medium text-slate-400 mb-4">Cumulative P&L Performance</h3>
          <div className="h-[250px] w-full">
            {chartData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <LineChart data={chartData}>
                  <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
                  <XAxis
                    dataKey="date"
                    stroke="#94a3b8"
                    fontSize={10}
                    tickLine={false}
                    axisLine={false}
                  />
                  <YAxis
                    stroke="#94a3b8"
                    fontSize={10}
                    tickLine={false}
                    axisLine={false}
                    tickFormatter={(v) => `$${v}`}
                  />
                  <Tooltip
                    contentStyle={{ backgroundColor: '#1e293b', border: '1px solid #334155', borderRadius: '8px' }}
                    itemStyle={{ color: '#38bdf8' }}
                  />
                  <Line
                    type="monotone"
                    dataKey="pnl"
                    stroke="#38bdf8"
                    strokeWidth={2}
                    dot={{ r: 3, fill: '#38bdf8' }}
                    activeDot={{ r: 5 }}
                  />
                </LineChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex items-center justify-center text-slate-500 text-sm italic">
                Insufficient data for chart
              </div>
            )}
          </div>
        </div>

        {/* City Breakdown */}
        <div className="bg-slate-800 rounded-xl border border-slate-700 overflow-hidden">
          <div className="px-5 py-4 border-b border-slate-700">
            <h3 className="text-sm font-medium text-white">City Performance</h3>
          </div>
          <div className="max-h-[250px] overflow-y-auto">
            <table className="w-full text-xs">
              <thead className="text-slate-500 uppercase bg-slate-800/50 sticky top-0">
                <tr>
                  <th className="px-4 py-2 text-left">City</th>
                  <th className="px-4 py-2 text-center">W/L</th>
                  <th className="px-4 py-2 text-right">P&L</th>
                </tr>
              </thead>
              <tbody>
                {cityBreakdown.map(([city, data]) => (
                  <tr key={city} className="border-b border-slate-700/50">
                    <td className="px-4 py-3 font-medium">{city}</td>
                    <td className="px-4 py-3 text-center text-slate-400">{data.w}W - {data.l}L</td>
                    <td className={`px-4 py-3 text-right font-mono ${data.pnl >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                      {data.pnl >= 0 ? '+' : ''}${data.pnl.toFixed(2)}
                    </td>
                  </tr>
                ))}
                {cityBreakdown.length === 0 && (
                   <tr>
                     <td colSpan={3} className="px-4 py-8 text-center text-slate-500 italic">No settled trades</td>
                   </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>

      {/* Model Confidence Accuracy */}
      {(confidenceAccuracy.high || confidenceAccuracy.medium || confidenceAccuracy.low) && (
        <div className="bg-slate-800 rounded-xl border border-slate-700 overflow-hidden">
          <div className="px-5 py-4 border-b border-slate-700">
            <h3 className="text-sm font-medium text-white">Model Confidence Accuracy</h3>
          </div>
          <div className="grid grid-cols-3 divide-x divide-slate-700">
            {(['high', 'medium', 'low'] as const).map(level => {
              const data = confidenceAccuracy[level]
              const colors = { high: 'text-emerald-400', medium: 'text-yellow-400', low: 'text-slate-400' }
              return (
                <div key={level} className="px-5 py-4 text-center">
                  <p className={`text-xs uppercase font-medium ${colors[level]}`}>{level}</p>
                  {data ? (
                    <>
                      <p className="text-xl font-bold mt-1 text-white">{data.pct}%</p>
                      <p className="text-xs text-slate-500 mt-0.5">{data.total} trades</p>
                    </>
                  ) : (
                    <p className="text-xl font-bold mt-1 text-slate-600">—</p>
                  )}
                </div>
              )
            })}
          </div>
        </div>
      )}

      {/* Controls */}
      <div className="flex justify-between items-center">
        <h2 className="text-lg font-semibold text-white">Trade History ({trades.length})</h2>
        <button
          onClick={settle}
          disabled={settling || open.length === 0}
          className="px-4 py-2 bg-slate-700 hover:bg-slate-600 disabled:opacity-40 rounded-lg text-sm transition-colors"
        >
          {settling ? 'Settling...' : `Check ${open.length} Open Trade${open.length !== 1 ? 's' : ''}`}
        </button>
      </div>

      {trades.length === 0 ? (
        <div className="bg-slate-800 rounded-xl border border-slate-700 px-6 py-12 text-center">
          <p className="text-4xl mb-3">📝</p>
          <p className="text-slate-300">No paper trades yet</p>
          <p className="text-slate-500 text-sm mt-1">Trades are logged automatically when signals fire.</p>
        </div>
      ) : (
        <div className="bg-slate-800 rounded-xl border border-slate-700 overflow-hidden overflow-x-auto">
          <table className="w-full text-sm">
            <thead>
              <tr className="text-slate-400 text-left border-b border-slate-700 text-xs uppercase">
                <th className="px-5 py-3">Date</th>
                <th className="px-5 py-3">City</th>
                <th className="px-5 py-3">Trade</th>
                <th className="px-5 py-3">Entry</th>
                <th className="px-5 py-3">Size</th>
                <th className="px-5 py-3">Gap</th>
                <th className="px-5 py-3">Kelly</th>
                <th className="px-5 py-3">Status</th>
                <th className="px-5 py-3">P&L</th>
              </tr>
            </thead>
            <tbody>
              {[...normalizedTrades].reverse().map(t => (
                <tr key={t.id} className="border-b border-slate-700/50 hover:bg-slate-700/20">
                  <td className="px-5 py-3 text-slate-400">{t.target_date}</td>
                  <td className="px-5 py-3 font-semibold">{t.city}</td>
                  <td className="px-5 py-3">
                    <span className={`px-2 py-0.5 rounded text-xs font-bold mr-2 ${t.side === 'YES' ? 'bg-emerald-500/20 text-emerald-400' : 'bg-red-500/20 text-red-400'}`}>{t.side}</span>
                    <span className="font-mono text-sky-400 text-xs">{t.ticker.split('-').slice(-1)[0]}</span>
                  </td>
                  <td className="px-5 py-3 font-mono">${t.entry_price.toFixed(2)}</td>
                  <td className="px-5 py-3 text-xs font-mono text-slate-300">
                    {t.simulated_contracts} × ${t.entry_price.toFixed(2)} = ${t.simulated_cost.toFixed(2)}
                  </td>
                  <td className="px-5 py-3">
                    <span className={t.gap_f > 0 ? 'text-orange-400' : 'text-blue-400'}>
                      {t.gap_f > 0 ? '+' : ''}{t.gap_f}°F
                    </span>
                  </td>
                  <td className="px-5 py-3">
                    <span className="font-mono text-xs">
                      {t.kelly_fraction != null ? `${(t.kelly_fraction * 100).toFixed(1)}%` : '—'}
                    </span>
                    {t.model_confidence && (
                      <ConfidenceBadge level={t.model_confidence} />
                    )}
                  </td>
                  <td className="px-5 py-3">
                    <StatusBadge status={t.status} />
                  </td>
                  <td className="px-5 py-3">
                    {t.pnl !== undefined ? (
                      <span className={`font-mono ${t.pnl >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                        {t.pnl >= 0 ? '+' : ''}${t.pnl.toFixed(2)}
                      </span>
                    ) : '—'}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  )
}

function ConfidenceBadge({ level }: { level: 'high' | 'medium' | 'low' }) {
  const colors = {
    high: 'bg-emerald-500/20 text-emerald-400',
    medium: 'bg-yellow-500/20 text-yellow-400',
    low: 'bg-slate-600/50 text-slate-400',
  }
  return <span className={`ml-1.5 px-1.5 py-0.5 rounded text-[10px] font-bold uppercase ${colors[level]}`}>{level[0]}</span>
}

function StatusBadge({ status }: { status: string }) {
  const map: Record<string, string> = {
    open: 'bg-yellow-500/20 text-yellow-400',
    won: 'bg-emerald-500/20 text-emerald-400',
    lost: 'bg-red-500/20 text-red-400',
    settled: 'bg-slate-500 text-slate-300',
    expired: 'bg-slate-600 text-slate-400',
  }
  return <span className={`px-2 py-0.5 rounded text-xs font-bold ${map[status] || ''}`}>{status.toUpperCase()}</span>
}

function BalanceCard({ label, value, positive }: { label: string; value: string; positive?: boolean }) {
  const color = positive === undefined ? 'text-white' : positive ? 'text-emerald-400' : 'text-red-400'
  return (
    <div className="bg-slate-800 rounded-xl border border-slate-700 px-6 py-5">
      <p className="text-slate-400 text-xs uppercase tracking-wider">{label}</p>
      <p className={`text-3xl font-bold mt-2 font-mono ${color}`}>{value}</p>
    </div>
  )
}

function MiniCard({ label, value, positive }: { label: string; value: string; positive?: boolean }) {
  const color = positive === undefined ? 'text-white' : positive ? 'text-emerald-400' : 'text-red-400'
  return (
    <div className="bg-slate-800 rounded-xl border border-slate-700 px-5 py-4">
      <p className="text-slate-400 text-xs">{label}</p>
      <p className={`text-xl font-bold mt-1 ${color}`}>{value}</p>
    </div>
  )
}
